/**
 * AppDialog — standardized dialog shell for non-confirm dialogs.
 *
 * Provides consistent title row (with optional close icon), content padding,
 * and action footer for content-heavy dialogs (forms, info panels, pickers).
 * For simple confirm prompts, use `ConfirmDialog` instead.
 */
import * as React from 'react';
import {
    Dialog,
    DialogActions,
    DialogContent,
    DialogTitle,
    IconButton,
    Stack,
} from '@mui/material';
import CloseIcon from '@mui/icons-material/Close';

export interface AppDialogProps {
    open: boolean;
    onClose: () => void;
    title: React.ReactNode;
    /** Content rendered inside DialogContent. */
    children: React.ReactNode;
    /** Optional footer (typically Cancel/Submit buttons). */
    actions?: React.ReactNode;
    /** When true, hides the close (X) icon in the title row. */
    hideCloseButton?: boolean;
    /** Dialog max width — defaults to 'sm'. */
    maxWidth?: 'xs' | 'sm' | 'md' | 'lg' | 'xl';
    /** Lock the dialog (close icon + backdrop ignored). */
    busy?: boolean;
    /** Disable padding on DialogContent (for full-bleed media). */
    disablePadding?: boolean;
}

export const AppDialog: React.FC<AppDialogProps> = ({
    open,
    onClose,
    title,
    children,
    actions,
    hideCloseButton = false,
    maxWidth = 'sm',
    busy = false,
    disablePadding = false,
}) => {
    const handleClose = () => {
        if (!busy) onClose();
    };

    return (
        <Dialog open={open} onClose={handleClose} maxWidth={maxWidth} fullWidth>
            <DialogTitle sx={{ pr: hideCloseButton ? undefined : 6 }}>
                <Stack direction="row" spacing={1} sx={{ alignItems: 'center', justifyContent: 'space-between' }}>
                    <span>{title}</span>
                    {!hideCloseButton && (
                        <IconButton
                            aria-label="Close"
                            onClick={onClose}
                            disabled={busy}
                            size="small"
                            sx={{ position: 'absolute', right: 8, top: 8 }}
                        >
                            <CloseIcon fontSize="small" />
                        </IconButton>
                    )}
                </Stack>
            </DialogTitle>
            <DialogContent dividers={!!actions} sx={disablePadding ? { p: 0 } : undefined}>
                {children}
            </DialogContent>
            {actions && <DialogActions>{actions}</DialogActions>}
        </Dialog>
    );
};

export default AppDialog;
